"use client";

import type { Transition } from "motion/react";
import { animate, motion } from "motion/react";
import {
  Children,
  isValidElement,
  memo,
  type ReactElement,
  type ReactNode,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import { type ArcDatum, buildArcs, buildRevealDelays } from "./sunburst";
import {
  defaultSunburstColors,
  opacityForRelativeDepth,
  type SunburstContextValue,
  SunburstProvider,
} from "./sunburst-context";
import type { SunburstNode } from "./sunburst-data";

export type { ArcDatum, Focus } from "./sunburst";
export type { SunburstNode } from "./sunburst-data";

const DEFAULT_HOVER_POP = 10;

function componentDisplayName(child: ReactElement): string {
  return (
    (child.type as { displayName?: string }).displayName ||
    (child.type as { name?: string }).name ||
    ""
  );
}

function isDefsComponent(child: ReactElement): boolean {
  const name = componentDisplayName(child);
  return (
    name.includes("Gradient") ||
    name.includes("Pattern") ||
    name === "LinearGradient" ||
    name === "RadialGradient"
  );
}

function isOutsideSvgComponent(name: string): boolean {
  return name === "SunburstBreadcrumb" || name === "SunburstHint";
}

function isSunburstSegment(
  child: ReactNode
): child is ReactElement<{ index: number }> {
  return (
    isValidElement(child) && componentDisplayName(child) === "SunburstSegment"
  );
}

/** Inner rings last so parent segments win hit testing at ring boundaries. */
function sortSunburstSegments(
  segments: ReactElement<{ index: number }>[],
  arcs: ArcDatum[]
): ReactElement<{ index: number }>[] {
  return [...segments].sort((a, b) => {
    const arcA = arcs[a.props.index];
    const arcB = arcs[b.props.index];
    const depthA = arcA?.depth ?? 0;
    const depthB = arcB?.depth ?? 0;
    if (depthA !== depthB) {
      return depthB - depthA;
    }
    return (b.props.index ?? 0) - (a.props.index ?? 0);
  });
}

export interface SunburstChartProps {
  data: SunburstNode;
  size?: number;
  /** Bump to replay the initialization animation. */
  playKey?: number;
  className?: string;
  /** Controlled focus node id for drill-down. */
  focusId?: string;
  /** Called when focus changes via segment click or breadcrumb. */
  onFocusChange?: (focusId: string) => void;
  /** Controlled hover — arc index in the arcs array. */
  hoveredIndex?: number | null;
  onHoverChange?: (index: number | null) => void;
  hoverPop?: number;
  enterTransition?: Transition;
  enterStaggerScale?: number;
  children: ReactNode;
}

const SunburstChartCore = memo(function SunburstChartCore({
  data,
  size = 520,
  playKey = 0,
  className,
  focusId: focusIdProp,
  onFocusChange,
  hoveredIndex: hoveredIndexProp,
  onHoverChange,
  hoverPop = DEFAULT_HOVER_POP,
  enterTransition,
  enterStaggerScale = 1,
  children,
}: SunburstChartProps) {
  const radius = size / 2;
  const containerRef = useRef<HTMLDivElement>(null);
  const { arcs, maxDepth, focusById, rootId } = useMemo(
    () => buildArcs(data),
    [data]
  );

  const [t, setT] = useState(0);
  const [internalHoveredArc, setInternalHoveredArc] = useState<ArcDatum | null>(
    null
  );
  const [internalHoveredIndex, setInternalHoveredIndex] = useState<
    number | null
  >(null);
  const growRef = useRef<Map<string, number>>(new Map());
  const [growTick, setGrowTick] = useState(0);

  const [internalFocusId, setInternalFocusId] = useState(rootId);
  const [prevFocusId, setPrevFocusId] = useState(rootId);
  const [zoomT, setZoomT] = useState(1);

  const isFocusControlled = focusIdProp !== undefined;
  const focusId = isFocusControlled ? focusIdProp : internalFocusId;

  const isHoverControlled = hoveredIndexProp !== undefined;
  const hoveredArcIndex = isHoverControlled
    ? hoveredIndexProp
    : internalHoveredIndex;
  const hoveredArc = useMemo(() => {
    if (hoveredArcIndex != null) {
      return arcs[hoveredArcIndex] ?? null;
    }
    return internalHoveredArc;
  }, [arcs, hoveredArcIndex, internalHoveredArc]);

  const setHoveredArcIndex = useCallback(
    (index: number | null) => {
      if (isHoverControlled) {
        onHoverChange?.(index);
      } else {
        setInternalHoveredIndex(index);
        setInternalHoveredArc(index == null ? null : (arcs[index] ?? null));
      }
    },
    [arcs, isHoverControlled, onHoverChange]
  );

  const setHoveredArc = useCallback(
    (arc: ArcDatum | null) => {
      setHoveredArcIndex(arc ? arc.arcIndex : null);
    },
    [setHoveredArcIndex]
  );

  const setFocusId = useCallback(
    (nextId: string) => {
      if (isFocusControlled) {
        onFocusChange?.(nextId);
      } else {
        setInternalFocusId(nextId);
      }
    },
    [isFocusControlled, onFocusChange]
  );

  const rootFocus = focusById.get(rootId);
  const focus = focusById.get(focusId) ?? rootFocus;
  const prevFocus = focusById.get(prevFocusId) ?? focus;

  useEffect(() => {
    if (!isFocusControlled) {
      setInternalFocusId(rootId);
    }
    setPrevFocusId(rootId);
    setZoomT(1);
  }, [rootId, isFocusControlled]);

  const delays = useMemo(() => buildRevealDelays(arcs), [arcs]);

  const prefersReduced = () =>
    typeof window !== "undefined" &&
    window.matchMedia?.("(prefers-reduced-motion: reduce)").matches;

  // biome-ignore lint/correctness/useExhaustiveDependencies: replay on data/playKey
  useEffect(() => {
    if (prefersReduced()) {
      setT(1);
      return;
    }
    setT(0);
    const controls = animate(0, 1, {
      duration: 1.85,
      ease: [0.22, 1, 0.36, 1],
      onUpdate: setT,
      onComplete: () => setT(1),
    });
    return () => controls.stop();
  }, [arcs, playKey]);

  const growControls = useRef<ReturnType<typeof animate> | null>(null);
  const zoomControls = useRef<ReturnType<typeof animate> | null>(null);
  const zoomGen = useRef(0);

  // biome-ignore lint/correctness/useExhaustiveDependencies: prefersReduced reads matchMedia at call time
  const zoomTo = useCallback(
    (nextId: string) => {
      if (nextId === focusId) {
        return;
      }
      setHoveredArc(null);
      growControls.current?.stop();
      growRef.current = new Map();
      setGrowTick((n) => n + 1);
      setPrevFocusId(focusId);
      setFocusId(nextId);
      zoomControls.current?.stop();
      const gen = ++zoomGen.current;
      if (prefersReduced()) {
        setZoomT(1);
        return;
      }
      setZoomT(0);
      zoomControls.current = animate(0, 1, {
        duration: 0.75,
        ease: [0.22, 1, 0.36, 1],
        onUpdate: (value) => {
          if (zoomGen.current === gen) {
            setZoomT(value);
          }
        },
        onComplete: () => {
          if (zoomGen.current === gen) {
            setZoomT(1);
            setPrevFocusId(nextId);
          }
        },
      });
    },
    [focusId, setFocusId, setHoveredArc]
  );

  const isDescendant = useCallback(
    (d: ArcDatum, ancestorId: string) =>
      d.id === ancestorId || d.id.startsWith(`${ancestorId} / `),
    []
  );

  const isRelated = useCallback(
    (d: ArcDatum) => {
      if (!hoveredArc) {
        return true;
      }
      return (
        isDescendant(d, hoveredArc.id) || hoveredArc.id.startsWith(`${d.id} / `)
      );
    },
    [hoveredArc, isDescendant]
  );

  // biome-ignore lint/correctness/useExhaustiveDependencies: grow targets from hovered subtree
  useEffect(() => {
    const targets = new Map<string, number>();
    for (const d of arcs) {
      if (hoveredArc && isDescendant(d, hoveredArc.id) && !d.hasChildren) {
        targets.set(d.id, hoverPop);
      }
    }
    const starts = new Map(growRef.current);
    const ids = new Set<string>([...starts.keys(), ...targets.keys()]);

    growControls.current?.stop();

    if (prefersReduced()) {
      growRef.current = targets;
      setGrowTick((n) => n + 1);
      return;
    }

    growControls.current = animate(0, 1, {
      duration: 0.42,
      ease: [0.22, 1, 0.36, 1],
      onUpdate: (p) => {
        const next = new Map<string, number>();
        for (const id of ids) {
          const start = starts.get(id) ?? 0;
          const target = targets.get(id) ?? 0;
          const val = start + (target - start) * p;
          if (val > 0.01) {
            next.set(id, val);
          }
        }
        growRef.current = next;
        setGrowTick((n) => n + 1);
      },
    });
    return () => growControls.current?.stop();
  }, [hoveredArc, arcs, hoverPop, isDescendant]);

  const getColor = useCallback((categoryIndex: number, nodeColor?: string) => {
    if (nodeColor) {
      return nodeColor;
    }
    return defaultSunburstColors[
      categoryIndex % defaultSunburstColors.length
    ] as string;
  }, []);

  const getFill = useCallback(
    (arcIndex: number, fillOverride?: string, colorOverride?: string) => {
      if (fillOverride) {
        return fillOverride;
      }
      const arc = arcs[arcIndex];
      if (!arc) {
        return defaultSunburstColors[0] as string;
      }
      return (
        colorOverride ?? arc.fill ?? arc.color ?? getColor(arc.categoryIndex)
      );
    },
    [arcs, getColor]
  );

  const getFillOpacity = useCallback(
    (relativeDepth: number, override?: number) =>
      override ?? opacityForRelativeDepth(relativeDepth),
    []
  );

  // biome-ignore lint/correctness/useExhaustiveDependencies: growTick forces re-read from growRef
  const growAmountForArc = useCallback(
    (arcId: string) => growRef.current.get(arcId) ?? 0,
    [growTick]
  );

  if (!(focus && prevFocus)) {
    return null;
  }

  const childArray = Children.toArray(children);
  const defsChildren = childArray.filter(
    (child): child is ReactElement =>
      isValidElement(child) && isDefsComponent(child)
  );

  const outsideChildren: ReactNode[] = [];
  const svgChildren: ReactNode[] = [];

  for (const child of childArray) {
    if (!isValidElement(child)) {
      svgChildren.push(child);
      continue;
    }
    if (isDefsComponent(child)) {
      continue;
    }
    const name = componentDisplayName(child);
    if (isOutsideSvgComponent(name)) {
      outsideChildren.push(child);
    } else {
      svgChildren.push(child);
    }
  }

  const segmentChildren = svgChildren.filter(isSunburstSegment);
  const otherSvgChildren = svgChildren.filter(
    (child) => !isSunburstSegment(child)
  );
  const orderedSegments = sortSunburstSegments(segmentChildren, arcs);
  const orderedSvgChildren = [...orderedSegments, ...otherSvgChildren];

  const providerValue: SunburstContextValue = {
    data,
    arcs,
    focusById,
    rootId,
    maxDepth,
    radius,
    size,
    focus,
    prevFocus,
    focusId,
    zoomTo,
    t,
    zoomT,
    delays,
    growAmountForArc,
    getColor,
    getFill,
    getFillOpacity,
    isRelated,
    isDescendant,
    enterTransition,
    enterStaggerScale,
    playKey,
    hoverPop,
    containerRef,
    hoveredArcIndex,
    setHoveredArcIndex,
    hoveredArc,
    setHoveredArc,
  };

  return (
    <SunburstProvider value={providerValue}>
      <div
        className={className}
        ref={containerRef}
        style={{ maxWidth: "100%", width: size }}
      >
        {outsideChildren.filter(
          (child) =>
            isValidElement(child) &&
            componentDisplayName(child) === "SunburstBreadcrumb"
        )}
        <motion.svg
          animate={{ opacity: 1, scale: 1 }}
          aria-label={`Sunburst chart of ${data.name}`}
          initial={{ opacity: 0, scale: 0.96 }}
          onPointerLeave={() => setHoveredArc(null)}
          role="img"
          style={{ display: "block", overflow: "visible" }}
          transition={{ duration: 0.65, ease: [0.22, 1, 0.36, 1] }}
          viewBox={`${-radius} ${-radius} ${size} ${size}`}
          width="100%"
        >
          {defsChildren.length > 0 ? <defs>{defsChildren}</defs> : null}
          {orderedSvgChildren}
        </motion.svg>
        {outsideChildren.filter(
          (child) =>
            isValidElement(child) &&
            componentDisplayName(child) === "SunburstHint"
        )}
      </div>
    </SunburstProvider>
  );
});

export function SunburstChart(props: SunburstChartProps) {
  return <SunburstChartCore {...props} />;
}

SunburstChart.displayName = "SunburstChart";

"use client";

import type { Transition } from "motion/react";
import {
  createContext,
  type ReactNode,
  type RefObject,
  useContext,
  useMemo,
} from "react";
import type { ArcDatum, Focus } from "./sunburst";
import type { SunburstNode } from "./sunburst-data";

export const sunburstCssVars = {
  background: "var(--chart-background)",
  foreground: "var(--chart-foreground)",
  foregroundMuted: "var(--chart-foreground-muted)",
  label: "var(--chart-label)",
  ring: "var(--chart-background)",
  slice1: "var(--chart-1)",
  slice2: "var(--chart-2)",
  slice3: "var(--chart-3)",
  slice4: "var(--chart-4)",
  slice5: "var(--chart-5)",
};

export const defaultSunburstColors = [
  sunburstCssVars.slice1,
  sunburstCssVars.slice2,
  sunburstCssVars.slice3,
  sunburstCssVars.slice4,
  sunburstCssVars.slice5,
];

const OPACITY_STEP = 0.15;
const OPACITY_FLOOR = 0.45;

/** Relative depth within the current focus view (1 = innermost visible ring). */
export function opacityForRelativeDepth(relativeDepth: number): number {
  if (relativeDepth <= 1) {
    return 1;
  }
  return Math.max(OPACITY_FLOOR, 1 - (relativeDepth - 1) * OPACITY_STEP);
}

export interface SunburstHoverContextValue {
  hoveredArcIndex: number | null;
  setHoveredArcIndex: (index: number | null) => void;
  hoveredArc: ArcDatum | null;
  setHoveredArc: (arc: ArcDatum | null) => void;
}

export interface SunburstStableContextValue {
  data: SunburstNode;
  arcs: ArcDatum[];
  focusById: Map<string, Focus>;
  rootId: string;
  maxDepth: number;
  radius: number;
  size: number;

  focus: Focus;
  prevFocus: Focus;
  focusId: string;
  zoomTo: (nextId: string) => void;

  t: number;
  zoomT: number;
  delays: Map<string, number>;
  growAmountForArc: (arcId: string) => number;

  getColor: (categoryIndex: number, nodeColor?: string) => string;
  getFill: (
    arcIndex: number,
    fillOverride?: string,
    colorOverride?: string
  ) => string;
  getFillOpacity: (relativeDepth: number, override?: number) => number;

  isRelated: (arc: ArcDatum) => boolean;
  isDescendant: (arc: ArcDatum, ancestorId: string) => boolean;

  enterTransition?: Transition;
  enterStaggerScale: number;
  playKey: number;
  hoverPop: number;

  containerRef: RefObject<HTMLDivElement | null>;
}

export type SunburstContextValue = SunburstStableContextValue &
  SunburstHoverContextValue;

const SunburstStableContext = createContext<SunburstStableContextValue | null>(
  null
);
const SunburstHoverContext = createContext<SunburstHoverContextValue | null>(
  null
);

export function SunburstProvider({
  children,
  value,
}: {
  children: ReactNode;
  value: SunburstContextValue;
}) {
  const stable = useMemo<SunburstStableContextValue>(
    () => ({
      data: value.data,
      arcs: value.arcs,
      focusById: value.focusById,
      rootId: value.rootId,
      maxDepth: value.maxDepth,
      radius: value.radius,
      size: value.size,
      focus: value.focus,
      prevFocus: value.prevFocus,
      focusId: value.focusId,
      zoomTo: value.zoomTo,
      t: value.t,
      zoomT: value.zoomT,
      delays: value.delays,
      growAmountForArc: value.growAmountForArc,
      getColor: value.getColor,
      getFill: value.getFill,
      getFillOpacity: value.getFillOpacity,
      isRelated: value.isRelated,
      isDescendant: value.isDescendant,
      enterTransition: value.enterTransition,
      enterStaggerScale: value.enterStaggerScale,
      playKey: value.playKey,
      hoverPop: value.hoverPop,
      containerRef: value.containerRef,
    }),
    [
      value.data,
      value.arcs,
      value.focusById,
      value.rootId,
      value.maxDepth,
      value.radius,
      value.size,
      value.focus,
      value.prevFocus,
      value.focusId,
      value.zoomTo,
      value.t,
      value.zoomT,
      value.delays,
      value.growAmountForArc,
      value.getColor,
      value.getFill,
      value.getFillOpacity,
      value.isRelated,
      value.isDescendant,
      value.enterTransition,
      value.enterStaggerScale,
      value.playKey,
      value.hoverPop,
      value.containerRef,
    ]
  );

  const hover = useMemo<SunburstHoverContextValue>(
    () => ({
      hoveredArcIndex: value.hoveredArcIndex,
      setHoveredArcIndex: value.setHoveredArcIndex,
      hoveredArc: value.hoveredArc,
      setHoveredArc: value.setHoveredArc,
    }),
    [
      value.hoveredArcIndex,
      value.setHoveredArcIndex,
      value.hoveredArc,
      value.setHoveredArc,
    ]
  );

  return (
    <SunburstStableContext.Provider value={stable}>
      <SunburstHoverContext.Provider value={hover}>
        {children}
      </SunburstHoverContext.Provider>
    </SunburstStableContext.Provider>
  );
}

export function useSunburstStable() {
  const ctx = useContext(SunburstStableContext);
  if (!ctx) {
    throw new Error("useSunburstStable must be used within SunburstChart");
  }
  return ctx;
}

export function useSunburstHover() {
  const ctx = useContext(SunburstHoverContext);
  if (!ctx) {
    throw new Error("useSunburstHover must be used within SunburstChart");
  }
  return ctx;
}

"use client";

import { memo } from "react";
import { arcPath, localProgress, transitionGeometry } from "./sunburst";
import {
  sunburstCssVars,
  useSunburstHover,
  useSunburstStable,
} from "./sunburst-context";

export interface SunburstSegmentProps {
  index: number;
  /** Optional color override */
  color?: string;
  /** Optional fill override (patterns/gradients) */
  fill?: string;
  /** Optional fill opacity override */
  fillOpacity?: number;
}

export const SunburstSegment = memo(function SunburstSegment({
  index,
  color: colorProp,
  fill: fillProp,
  fillOpacity: fillOpacityProp,
}: SunburstSegmentProps) {
  const {
    arcs,
    focus,
    prevFocus,
    maxDepth,
    radius,
    zoomT,
    t,
    delays,
    growAmountForArc,
    getFill,
    getFillOpacity,
    isRelated,
    zoomTo,
  } = useSunburstStable();
  const { setHoveredArc, setHoveredArcIndex } = useSunburstHover();

  const arc = arcs[index];
  if (!arc) {
    return null;
  }

  const base = transitionGeometry(
    arc,
    prevFocus,
    focus,
    maxDepth,
    radius,
    zoomT
  );
  if (!base) {
    return null;
  }

  const gAmt = growAmountForArc(arc.id);
  const visualGeometry =
    gAmt > 0 ? { ...base, outerR: base.outerR + gAmt } : base;

  const lp = localProgress(t, delays.get(arc.id) ?? 0);
  const reveal = lp >= 1 ? 1 : lp;
  const hitPath = arcPath(base, reveal);
  const visualPath = arcPath(visualGeometry, reveal);
  if (!(hitPath && visualPath)) {
    return null;
  }

  const relativeDepth = arc.depth - focus.depth;
  const segmentFill = getFill(index, fillProp, colorProp);
  const fillOpacity = fillOpacityProp ?? getFillOpacity(relativeDepth);
  const related = isRelated(arc);
  const segmentOpacity = lp * (related ? 1 : 0.25);

  return (
    <g
      style={{
        cursor: arc.hasChildren ? "pointer" : "default",
        opacity: segmentOpacity,
        transition: "opacity 320ms cubic-bezier(0.22, 1, 0.36, 1)",
      }}
    >
      {/* Stable hit target — ring band without hover grow (matches PieSlice pattern) */}
      {/* biome-ignore lint/a11y/noStaticElementInteractions: Sunburst segment drill-down */}
      <path
        d={hitPath}
        fill="transparent"
        onClick={() => arc.hasChildren && zoomTo(arc.id)}
        onPointerEnter={() => {
          setHoveredArc(arc);
          setHoveredArcIndex(index);
        }}
        pointerEvents="auto"
      />
      {/* Visible segment — may grow on hover; no pointer events */}
      <path
        d={visualPath}
        fill={segmentFill}
        fillOpacity={fillOpacity}
        pointerEvents="none"
        stroke={sunburstCssVars.ring}
        strokeLinejoin="round"
        strokeWidth={1}
      />
    </g>
  );
});

SunburstSegment.displayName = "SunburstSegment";

"use client";

import { memo } from "react";
import { ringOptions } from "./sunburst";
import { sunburstCssVars, useSunburstStable } from "./sunburst-context";

export interface SunburstCenterProps {
  className?: string;
}

export const SunburstCenter = memo(function SunburstCenter({
  className,
}: SunburstCenterProps) {
  const { focus, prevFocus, maxDepth, radius, zoomT, zoomTo, getColor } =
    useSunburstStable();

  const { centerR } = ringOptions(focus.depth, maxDepth, radius);
  const liveCenterR =
    centerR * zoomT +
    ringOptions(prevFocus.depth, maxDepth, radius).centerR * (1 - zoomT);

  if (liveCenterR <= 1) {
    return null;
  }

  const centerColor =
    focus.depth === 0
      ? sunburstCssVars.background
      : getColor(focus.categoryIndex);

  return (
    /* biome-ignore lint/a11y/noStaticElementInteractions: Center zoom-out control */
    <circle
      className={className}
      cx={0}
      cy={0}
      fill={centerColor}
      onClick={() => focus.parentId && zoomTo(focus.parentId)}
      r={Math.max(liveCenterR - 2, 0)}
      stroke={sunburstCssVars.ring}
      strokeWidth={1}
      style={{ cursor: focus.parentId ? "pointer" : "default" }}
    />
  );
});

SunburstCenter.displayName = "SunburstCenter";

"use client";

import { memo, type ReactNode, useMemo } from "react";
import type { Focus } from "./sunburst";
import { useSunburstStable } from "./sunburst-context";

export interface SunburstBreadcrumbItem {
  id: string;
  label: string;
  isCurrent: boolean;
}

export function useSunburstBreadcrumbItems() {
  const { data, focus, focusById, rootId, zoomTo } = useSunburstStable();

  const items = useMemo((): SunburstBreadcrumbItem[] => {
    const crumbs: Focus[] = [];
    let cur: Focus | undefined = focus;
    while (cur) {
      crumbs.unshift(cur);
      cur = cur.parentId ? focusById.get(cur.parentId) : undefined;
    }

    return crumbs.map((c, index) => ({
      id: c.id,
      label: c.id === rootId ? data.name : c.name,
      isCurrent: index === crumbs.length - 1,
    }));
  }, [data.name, focus, focusById, rootId]);

  return { items, zoomTo };
}

export interface SunburstBreadcrumbProps {
  className?: string;
  children: ReactNode;
}

export const SunburstBreadcrumb = memo(function SunburstBreadcrumb({
  className,
  children,
}: SunburstBreadcrumbProps) {
  return (
    <nav aria-label="Drill-down path" className={className ?? "mb-4"}>
      {children}
    </nav>
  );
});

SunburstBreadcrumb.displayName = "SunburstBreadcrumb";

"use client";

import { memo, type ReactNode } from "react";
import type { ArcDatum, Focus } from "./sunburst";
import { useSunburstHover, useSunburstStable } from "./sunburst-context";

export interface SunburstHintContext {
  hintText: string;
  hoveredArc: ArcDatum | null;
  focus: Focus;
}

export interface SunburstHintProps {
  className?: string;
  children?: ReactNode | ((context: SunburstHintContext) => ReactNode);
}

export const SunburstHint = memo(function SunburstHint({
  className,
  children,
}: SunburstHintProps) {
  const { focus } = useSunburstStable();
  const { hoveredArc } = useSunburstHover();

  const hintText = (() => {
    if (hoveredArc) {
      return hoveredArc.trail.join("  ›  ");
    }
    if (focus.depth === 0) {
      return "Click a segment to zoom in · hover to inspect";
    }
    return "Click the center to zoom out";
  })();

  const context: SunburstHintContext = { hintText, hoveredArc, focus };

  let content: ReactNode;
  if (typeof children === "function") {
    content = children(context);
  } else if (children == null) {
    content = hintText;
  } else {
    content = children;
  }

  return (
    <div
      aria-live="polite"
      className={
        className ?? "mt-3 min-h-5 text-center text-muted-foreground text-sm"
      }
      style={{ minHeight: 20 }}
    >
      {content}
    </div>
  );
});

SunburstHint.displayName = "SunburstHint";

"use client";

import { memo } from "react";
import {
  geomCentroidAngle,
  geomCentroidRadius,
  localProgress,
  transitionGeometry,
} from "./sunburst";
import { sunburstCssVars, useSunburstStable } from "./sunburst-context";

export interface SunburstLabelsProps {
  fontSize?: number;
  fill?: string;
  stroke?: string;
  strokeWidth?: number;
  className?: string;
}

const LABEL_REVEAL_LAG = 0.18;

export const SunburstLabels = memo(function SunburstLabels({
  fontSize = 11,
  fill = sunburstCssVars.label,
  stroke = sunburstCssVars.background,
  strokeWidth = 2.5,
  className,
}: SunburstLabelsProps) {
  const {
    arcs,
    focus,
    prevFocus,
    maxDepth,
    radius,
    zoomT,
    t,
    delays,
    growAmountForArc,
    isRelated,
  } = useSunburstStable();

  return (
    <g className={className}>
      {arcs.map((arc) => {
        const base = transitionGeometry(
          arc,
          prevFocus,
          focus,
          maxDepth,
          radius,
          zoomT
        );
        if (!base) {
          return null;
        }
        const gAmt = growAmountForArc(arc.id);
        const g = gAmt > 0 ? { ...base, outerR: base.outerR + gAmt } : base;
        const angleSpan = g.a1 - g.a0;
        const r = geomCentroidRadius(g);
        if (angleSpan * r < 26 || g.outerR - g.innerR < 16) {
          return null;
        }
        if (!isRelated(arc)) {
          return null;
        }

        const mid = geomCentroidAngle(g);
        const x = Math.sin(mid) * r;
        const y = -Math.cos(mid) * r;
        let deg = (mid * 180) / Math.PI - 90;
        if (deg > 90) {
          deg -= 180;
        }
        if (deg < -90) {
          deg += 180;
        }

        const segmentDelay = delays.get(arc.id) ?? 0;
        const segmentReveal = localProgress(t, segmentDelay);
        const labelDelay = Math.min(0.98, segmentDelay + LABEL_REVEAL_LAG);
        const labelOpacity =
          segmentReveal > 0.05 ? localProgress(t, labelDelay) : 0;

        const labelStyle: React.CSSProperties = {
          fill,
          fontFamily: "inherit",
          fontSize,
          fontWeight: 600,
          opacity: labelOpacity,
        };
        if (strokeWidth > 0) {
          labelStyle.paintOrder = "stroke";
          labelStyle.stroke = stroke;
          labelStyle.strokeLinejoin = "round";
          labelStyle.strokeWidth = strokeWidth;
        }

        return (
          <text
            dominantBaseline="middle"
            key={`label-${arc.id}`}
            pointerEvents="none"
            style={labelStyle}
            textAnchor="middle"
            transform={`rotate(${deg} ${x} ${y})`}
            x={x}
            y={y}
          >
            {arc.name}
          </text>
        );
      })}
    </g>
  );
});

SunburstLabels.displayName = "SunburstLabels";

import type { SunburstNode } from "./sunburst-data";

export interface ArcDatum {
  id: string;
  name: string;
  depth: number;
  value: number;
  categoryIndex: number;
  hasChildren: boolean;
  trail: string[];
  parentId: string | null;
  a0: number;
  a1: number;
  /** Stable index for Studio layer wiring. */
  arcIndex: number;
  /** Optional color override from data node. */
  color?: string;
  /** Optional fill override from data node (patterns). */
  fill?: string;
}

export interface Focus {
  id: string;
  name: string;
  depth: number;
  parentId: string | null;
  categoryIndex: number;
  a0: number;
  a1: number;
}

export interface ArcGeometry {
  a0: number;
  a1: number;
  innerR: number;
  outerR: number;
}

const TOP = -Math.PI / 2;
const TWO_PI = 2 * Math.PI;
const ID_SEP = " / ";

function nodeId(parentId: string | null, name: string): string {
  return parentId ? `${parentId}${ID_SEP}${name}` : name;
}

export function sumValues(node: SunburstNode): number {
  if (node.children?.length) {
    return node.children.reduce((sum, child) => sum + sumValues(child), 0);
  }
  return node.value ?? 0;
}

interface BuildContext {
  arcs: ArcDatum[];
  focusById: Map<string, Focus>;
  maxDepth: number;
  rootId: string;
  arcIndex: number;
}

function layoutNode(
  node: SunburstNode,
  id: string,
  depth: number,
  a0: number,
  a1: number,
  parentId: string | null,
  categoryIndex: number,
  trail: string[],
  ctx: BuildContext
) {
  const value = sumValues(node);
  const hasChildren = Boolean(node.children?.length);

  if (depth > 0) {
    ctx.arcs.push({
      id,
      name: node.name,
      depth,
      value,
      categoryIndex,
      hasChildren,
      trail: [...trail, node.name],
      parentId,
      a0,
      a1,
      arcIndex: ctx.arcIndex,
      color: node.color,
      fill: node.fill,
    });
    ctx.arcIndex += 1;
  }

  ctx.focusById.set(id, {
    id,
    name: node.name,
    depth,
    parentId,
    categoryIndex,
    a0,
    a1,
  });
  ctx.maxDepth = Math.max(ctx.maxDepth, depth);

  if (!(hasChildren && node.children?.length)) {
    return;
  }

  const span = a1 - a0;
  let cursor = a0;
  for (const [index, child] of node.children.entries()) {
    const childValue = sumValues(child);
    const childSpan = value > 0 ? (childValue / value) * span : 0;
    const childId = nodeId(id, child.name);
    const childCategory = depth === 0 ? index : categoryIndex;
    layoutNode(
      child,
      childId,
      depth + 1,
      cursor,
      cursor + childSpan,
      id,
      childCategory,
      depth === 0 ? [node.name] : trail,
      ctx
    );
    cursor += childSpan;
  }
}

function toRadians(normalized: number): number {
  return TOP + normalized * TWO_PI;
}

export function buildArcs(data: SunburstNode) {
  const rootId = data.name;
  const ctx: BuildContext = {
    arcs: [],
    focusById: new Map(),
    maxDepth: 0,
    rootId,
    arcIndex: 0,
  };

  layoutNode(data, rootId, 0, 0, 1, null, 0, [], ctx);

  for (const arc of ctx.arcs) {
    arc.a0 = toRadians(arc.a0);
    arc.a1 = toRadians(arc.a1);
  }
  for (const focus of ctx.focusById.values()) {
    focus.a0 = toRadians(focus.a0);
    focus.a1 = toRadians(focus.a1);
  }

  return {
    arcs: ctx.arcs,
    maxDepth: ctx.maxDepth,
    total: sumValues(data),
    focusById: ctx.focusById,
    rootId,
  };
}

export function ringOptions(
  focusDepth: number,
  maxDepth: number,
  radius: number
) {
  const oneLevelCenterR = radius / maxDepth;
  if (focusDepth === 0) {
    // Root view — segments fill from the center, no navigation hub gap.
    return { centerR: 0, ringWidth: oneLevelCenterR };
  }
  // Hub stays the same size from the first drill onward; only the rings widen.
  const centerR = oneLevelCenterR;
  const visibleRings = Math.max(1, maxDepth - focusDepth);
  const ringWidth = (radius - centerR) / visibleRings;
  return { centerR, ringWidth };
}

export function geometryFor(
  arc: ArcDatum,
  focus: Focus,
  maxDepth: number,
  radius: number
): ArcGeometry | null {
  if (arc.depth <= focus.depth) {
    return null;
  }
  if (arc.id !== focus.id && !arc.id.startsWith(`${focus.id}${ID_SEP}`)) {
    return null;
  }

  const { centerR, ringWidth } = ringOptions(focus.depth, maxDepth, radius);
  const relativeDepth = arc.depth - focus.depth;
  const focusSpan = focus.a1 - focus.a0;
  const mapAngle = (angle: number) => {
    if (focusSpan <= 1e-9) {
      return TOP;
    }
    return TOP + ((angle - focus.a0) / focusSpan) * TWO_PI;
  };

  return {
    a0: mapAngle(arc.a0),
    a1: mapAngle(arc.a1),
    innerR: centerR + (relativeDepth - 1) * ringWidth,
    outerR: centerR + relativeDepth * ringWidth,
  };
}

export function lerpGeometry(
  from: ArcGeometry,
  to: ArcGeometry,
  progress: number
): ArcGeometry {
  const t = Math.min(1, Math.max(0, progress));
  const fromMid = (from.a0 + from.a1) / 2;
  const toMid = (to.a0 + to.a1) / 2;
  const fromHalf = (from.a1 - from.a0) / 2;
  const toHalf = (to.a1 - to.a0) / 2;
  const mid = lerpAngle(fromMid, toMid, t);
  const half = fromHalf + (toHalf - fromHalf) * t;

  return {
    a0: mid - half,
    a1: mid + half,
    innerR: from.innerR + (to.innerR - from.innerR) * t,
    outerR: from.outerR + (to.outerR - from.outerR) * t,
  };
}

function lerpAngle(from: number, to: number, progress: number): number {
  let delta = to - from;
  while (delta > Math.PI) {
    delta -= TWO_PI;
  }
  while (delta < -Math.PI) {
    delta += TWO_PI;
  }
  return from + delta * progress;
}

function pointGeometry(source: ArcGeometry): ArcGeometry {
  const mid = (source.a0 + source.a1) / 2;
  const radius = (source.innerR + source.outerR) / 2;
  const pin = Math.max(0, Math.min(radius * 0.12, source.innerR));
  return { a0: mid, a1: mid, innerR: pin, outerR: pin };
}

/** Zoom morph — lerps matching arcs; entering/exiting arcs collapse to a point. */
export function transitionGeometry(
  arc: ArcDatum,
  fromFocus: Focus,
  toFocus: Focus,
  maxDepth: number,
  radius: number,
  progress: number
): ArcGeometry | null {
  const from = geometryFor(arc, fromFocus, maxDepth, radius);
  const to = geometryFor(arc, toFocus, maxDepth, radius);

  if (!(from || to)) {
    return null;
  }
  if (from && to) {
    return lerpGeometry(from, to, progress);
  }
  if (from) {
    return lerpGeometry(from, pointGeometry(from), progress);
  }
  if (to) {
    return lerpGeometry(pointGeometry(to), to, progress);
  }
  return null;
}

/** Normalized clockwise angle from 12 o'clock (0 → 1). */
export function clockwiseFraction(angle: number): number {
  let normalized = angle - TOP;
  if (normalized < 0) {
    normalized += TWO_PI;
  }
  return normalized / TWO_PI;
}

/** Ring-by-ring, clockwise stagger for the init reveal. */
export function buildRevealDelays(arcs: ArcDatum[]): Map<string, number> {
  const map = new Map<string, number>();
  const ringGap = 0.14;
  const ringSpan = 0.28;
  const byDepth = new Map<number, ArcDatum[]>();

  for (const arc of arcs) {
    const list = byDepth.get(arc.depth) ?? [];
    list.push(arc);
    byDepth.set(arc.depth, list);
  }

  for (const [depth, ringArcs] of byDepth) {
    const sorted = [...ringArcs].sort(
      (a, b) => clockwiseFraction(a.a0) - clockwiseFraction(b.a0)
    );
    const ringIndex = depth - 1;
    const baseDelay = ringIndex * ringGap;

    for (const [index, arc] of sorted.entries()) {
      const clockwiseSlot = sorted.length <= 1 ? 0 : index / sorted.length;
      map.set(arc.id, baseDelay + clockwiseSlot * ringSpan);
    }
  }

  return map;
}

export function arcPath(
  geometry: ArcGeometry,
  progress: number
): string | null {
  if (progress <= 0) {
    return null;
  }

  const p = Math.min(1, Math.max(0, progress));
  const { a0, a1, innerR, outerR } = geometry;

  if (p >= 1) {
    return arcPathFromGeometry(geometry);
  }

  const span = a1 - a0;

  // Clockwise sweep from the segment's leading edge (matches pie chart enter).
  const currentA0 = a0;
  const currentA1 = a0 + span * p;
  const currentInner = innerR < 1 ? 0 : innerR;
  const currentOuter = innerR < 1 ? outerR * p : innerR + (outerR - innerR) * p;

  return arcPathFromRadii(currentA0, currentA1, currentInner, currentOuter);
}

function arcPathFromGeometry(geometry: ArcGeometry): string | null {
  const { a0, a1, innerR, outerR } = geometry;
  return arcPathFromRadii(a0, a1, innerR, outerR);
}

function arcPathFromRadii(
  currentA0: number,
  currentA1: number,
  currentInner: number,
  currentOuter: number
): string | null {
  if (currentOuter - currentInner < 0.5 || currentA1 - currentA0 < 0.001) {
    return null;
  }

  const largeArc = currentA1 - currentA0 > Math.PI ? 1 : 0;
  const outerX0 = Math.sin(currentA0) * currentOuter;
  const outerY0 = -Math.cos(currentA0) * currentOuter;
  const outerX1 = Math.sin(currentA1) * currentOuter;
  const outerY1 = -Math.cos(currentA1) * currentOuter;

  if (currentInner < 1) {
    return `M 0 0 L ${outerX0} ${outerY0} A ${currentOuter} ${currentOuter} 0 ${largeArc} 1 ${outerX1} ${outerY1} Z`;
  }

  const innerX1 = Math.sin(currentA1) * currentInner;
  const innerY1 = -Math.cos(currentA1) * currentInner;
  const innerX0 = Math.sin(currentA0) * currentInner;
  const innerY0 = -Math.cos(currentA0) * currentInner;

  return `M ${outerX0} ${outerY0} A ${currentOuter} ${currentOuter} 0 ${largeArc} 1 ${outerX1} ${outerY1} L ${innerX1} ${innerY1} A ${currentInner} ${currentInner} 0 ${largeArc} 0 ${innerX0} ${innerY0} Z`;
}

export function centroidAngle(arc: ArcDatum): number {
  return (arc.a0 + arc.a1) / 2;
}

export function geomCentroidAngle(geometry: ArcGeometry): number {
  return (geometry.a0 + geometry.a1) / 2;
}

export function geomCentroidRadius(geometry: ArcGeometry): number {
  return (geometry.innerR + geometry.outerR) / 2;
}

export function localProgress(progress: number, delay: number): number {
  if (progress <= delay) {
    return 0;
  }
  const remaining = 1 - delay;
  if (remaining <= 0) {
    return 1;
  }
  const raw = Math.min(1, (progress - delay) / remaining);
  return raw;
}

export interface SunburstNode {
  name: string;
  value?: number;
  color?: string;
  /** Optional fill override for patterns/gradients (e.g., "url(#patternId)") */
  fill?: string;
  children?: SunburstNode[];
}
